// MARK: - Network Client Protocol

protocol NetworkClientProtocol {
    func request<T: Decodable>(endpoint: APIEndpoint, body: Encodable?, queryParams: [String: String]?) async throws -> T
}

// MARK: - Network Client

class NetworkClient: NetworkClientProtocol {
    
    static let shared = NetworkClient()
    
    private let session: URLSession
    private let environment: Environment
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    var tokenStorage: TokenStorageProtocol
    
    private var isRefreshing = false
    private var refreshContinuations: [CheckedContinuation<Void, Error>] = []
    private let lock = NSLock()
    
    init(
        environment: Environment = .development,
        tokenStorage: TokenStorageProtocol = KeychainTokenStorage(),
        sessionConfiguration: URLSessionConfiguration = .default
    ) {
        self.environment = environment
        self.tokenStorage = tokenStorage
        
        sessionConfiguration.timeoutIntervalForRequest = 30
        sessionConfiguration.timeoutIntervalForResource = 60
        sessionConfiguration.waitsForConnectivity = true
        
        self.session = URLSession(configuration: sessionConfiguration)
        
        self.decoder = JSONDecoder()
        self.decoder.dateDecodingStrategy = .iso8601
        
        self.encoder = JSONEncoder()
        self.encoder.dateEncodingStrategy = .iso8601
    }
    
    // MARK: - Public Request Method
    
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable? = nil,
        queryParams: [String: String]? = nil
    ) async throws -> T {
        let urlRequest = try buildRequest(endpoint: endpoint, body: body, queryParams: queryParams)
        return try await performRequest(urlRequest, endpoint: endpoint, body: body, queryParams: queryParams)
    }
    
    // MARK: - Private Helpers
    
    private func buildRequest(
        endpoint: APIEndpoint,
        body: Encodable?,
        queryParams: [String: String]?
    ) throws -> URLRequest {
        var urlString = environment.baseURL + endpoint.path
        
        if let queryParams = queryParams, !queryParams.isEmpty {
            var components = URLComponents(string: urlString)
            components?.queryItems = queryParams.map { URLQueryItem(name: $0.key, value: $0.value) }
            if let updatedURL = components?.string {
                urlString = updatedURL
            }
        }
        
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = endpoint.method.rawValue
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        // Add auth token for non-auth endpoints
        if let token = tokenStorage.accessToken {
            switch endpoint {
            case .login, .register:
                break
            default:
                request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
            }
        }
        
        if let body = body {
            request.httpBody = try encoder.encode(AnyEncodable(body))
        }
        
        return request
    }
    
    private func performRequest<T: Decodable>(
        _ request: URLRequest,
        endpoint: APIEndpoint,
        body: Encodable?,
        queryParams: [String: String]?
    ) async throws -> T {
        
        let data: Data
        let response: URLResponse
        
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            throw NetworkError.networkFailure(error)
        }
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.unknown
        }
        
        #if DEBUG
        logRequest(request, response: httpResponse, data: data)
        #endif
        
        switch httpResponse.statusCode {
        case 200...299:
            do {
                let decoded = try decoder.decode(T.self, from: data)
                return decoded
            } catch {
                throw NetworkError.decodingError(error)
            }
            
        case 401:
            // Attempt token refresh for non-auth endpoints
            switch endpoint {
            case .login, .register, .refreshToken:
                throw NetworkError.unauthorized
            default:
                try await refreshTokenIfNeeded()
                // Retry the original request with the new token
                let retryRequest = try buildRequest(endpoint: endpoint, body: body, queryParams: queryParams)
                return try await performRetryRequest(retryRequest)
            }
            
        default:
            let errorMessage = try? decoder.decode(APIErrorResponse.self, from: data)
            throw NetworkError.serverError(statusCode: httpResponse.statusCode, message: errorMessage?.message)
        }
    }
    
    private func performRetryRequest<T: Decodable>(_ request: URLRequest) async throws -> T {
        let data: Data
        let response: URLResponse
        
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            throw NetworkError.networkFailure(error)
        }
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.unknown
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            do {
                return try decoder.decode(T.self, from: data)
            } catch {
                throw NetworkError.decodingError(error)
            }
        case 401:
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        default:
            let errorMessage = try? decoder.decode(APIErrorResponse.self, from: data)
            throw NetworkError.serverError(statusCode: httpResponse.statusCode, message: errorMessage?.message)
        }
    }
    
    // MARK: - Token Refresh
    
    private func refreshTokenIfNeeded() async throws {
        lock.lock()
        
        if isRefreshing {
            lock.unlock()
            // Wait for the ongoing refresh to complete
            try await withCheckedThrowingContinuation { (continuation: CheckedContinuation<Void, Error>) in
                lock.lock()
                refreshContinuations.append(continuation)
                lock.unlock()
            }
            return
        }
        
        isRefreshing = true
        lock.unlock()
        
        defer {
            lock.lock()
            isRefreshing = false
            let continuations = refreshContinuations
            refreshContinuations.removeAll()
            lock.unlock()
            // Resume all waiting continuations
            for continuation in continuations {
                continuation.resume()
            }
        }
        
        guard let currentRefreshToken = tokenStorage.refreshToken else {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
        
        let refreshRequest = RefreshTokenRequest(refreshToken: currentRefreshToken)
        let urlRequest = try buildRefreshRequest(body: refreshRequest)
        
        let data: Data
        let response: URLResponse
        
        do {
            (data, response) = try await session.data(for: urlRequest)
        } catch {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
        
        do {
            let tokenResponse = try decoder.decode(RefreshTokenResponse.self, from: data)
            tokenStorage.accessToken = tokenResponse.accessToken
            tokenStorage.refreshToken = tokenResponse.refreshToken
        } catch {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
    }
    
    private func buildRefreshRequest(body: RefreshTokenRequest) throws -> URLRequest {
        let urlString = environment.baseURL + APIEndpoint.refreshToken.path
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }
        var request = URLRequest(url: url)
        request.httpMethod = HTTPMethod.post.rawValue
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        request.httpBody = try encoder.encode(body)
        return request
    }
    
    // MARK: - Logging
    
    private func logRequest(_ request: URLRequest, response: HTTPURLResponse, data: Data) {
        print("🌐 [\(request.httpMethod ?? "")] \(request.url?.absoluteString ?? "") → \(response.statusCode)")
        if let bodyData = request.httpBody, let bodyString = String(data: bodyData, encoding: .utf8) {
            print("📤 Body: \(bodyString)")
        }
        if let responseString = String(data: data, encoding: .utf8) {
            let truncated = responseString.prefix(500)
            print("📥 Response: \(truncated)")
        }
    }
}

// MARK: - AnyEncodable Wrapper

struct AnyEncodable: Encodable {
    private let encodeClosure: (Encoder) throws -> Void
    
    init(_ wrapped: Encodable) {
        self.encodeClosure = { encoder in
            try wrapped.encode(to: encoder)
        }
    }
    
    func encode(to encoder: Encoder) throws {
        try encodeClosure(encoder)
    }
}

// MARK: - Auth Service

protocol AuthServiceProtocol {
    func login(email: String, password: String) async throws -> AuthResponse
    func register(email: String, password: String, name: String) async throws -> AuthResponse
    func logout()
}

class AuthService: AuthServiceProtocol {
    
    private let client: NetworkClient
    
    init(client: NetworkClient = .shared) {
        self.client = client
    }
    
    func login(email: String, password: String) async throws -> AuthResponse {
        let body = LoginRequest(email: email, password: password)
        let response: AuthResponse = try await client.request(endpoint: .login, body: body)
        client.tokenStorage.accessToken = response.accessToken
        client.tokenStorage.refreshToken = response.refreshToken
        return response
    }
    
    func register(email: String, password: String, name: String) async throws -> AuthResponse {
        let body = RegisterRequest(email: email, password: password, name: name)
        let response: AuthResponse = try await client.request(endpoint: .register, body: body)
        client.tokenStorage.accessToken = response.accessToken
        client.tokenStorage.refreshToken = response.refreshToken
        return response
    }
    
    func logout() {
        client.tokenStorage.clearTokens()
    }
}

// MARK: - User Service

protocol UserServiceProtocol {
    func getCurrentUser() async throws -> User
    func getUser(id: String) async throws -> User
    func getUsers(page: Int, perPage: Int) async throws -> UsersResponse
}

class UserService: UserServiceProtocol {
    
    private let client: NetworkClientProtocol
    
    init(client: NetworkClientProtocol = NetworkClient.shared) {
        self.client = client
    }
    
    func getCurrentUser() async throws -> User {
        return try await client.request(endpoint: .getCurrentUser, body: nil, queryParams: nil)
    }
    
    func getUser(id: String) async throws -> User {
        return try await client.request(endpoint: .getUser(id: id), body: nil, queryParams: nil)
    }
    
    func getUsers(page: Int = 1, perPage: Int = 20) async throws -> UsersResponse {
        let params = [
            "page": "\(page)",
            "per_page": "\(perPage)"
        ]
        return try await client.request(endpoint: .getUsers, body: nil, queryParams: params)
    }
}

